#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X;
        scanf("%lld", &X);
        long long page = (X + 24) / 25;
        printf("%lld\n", page);
    }
    return 0;
}

